"use client";

import MainLayout from "@/components/MainLayout";
import ProductsByCategoryList from "@/components/ProductsByCategoryList";
import HomeProductsSection from "@/components/HomeProductsSection";
import NewsSection from "@/components/NewsSection";
import { useCategorySelection } from "@/components/layout/CategorySelectionContext";
import { useTranslations } from "next-intl";

function CategoryProductsPanel() {
  const t = useTranslations("Home");
  const { selectedCategoryId } = useCategorySelection();

  return (
    <div className="rounded-xl border border-slate-200 bg-white/90 p-4 shadow-sm">
      <div className="mb-3 flex items-center justify-between">
        <h2 className="text-lg font-semibold text-slate-900">
          {selectedCategoryId
            ? t("categoryProducts.title")
            : t("categoryProducts.selectCategory")}
        </h2>
      </div>
      {selectedCategoryId ? (
        <ProductsByCategoryList categoryId={selectedCategoryId} />
      ) : (
        <div className="rounded-lg border border-dashed border-slate-200 bg-slate-50 px-4 py-6 text-sm text-slate-600">
          {t("categoryProducts.emptyHint")}
        </div>
      )}
    </div>
  );
}

export default function HomePage() {
  const t = useTranslations("Home");

  return (
    <MainLayout>
      <section className="space-y-6">
        <div className="text-sm text-slate-600">{t("breadcrumb")}</div>

        {/* Hero Banner */}
        <div className="rounded-xl bg-gradient-to-r from-primary to-primary-light p-8 text-white shadow-lg sm:p-10">
          <div className="space-y-4">
            <p className="text-xs uppercase tracking-[0.3em] text-white/70">TME</p>
            <h1 className="text-3xl font-semibold sm:text-4xl">{t("hero.title")}</h1>
            <p className="max-w-2xl text-sm text-white/90">{t("hero.subtitle")}</p>
            <button className="rounded-full bg-slate-900/80 px-5 py-2 text-sm font-semibold uppercase tracking-widest text-white transition hover:bg-slate-900">
              {t("hero.button")}
            </button>
          </div>
        </div>

        {/* Category Products Panel */}
        <CategoryProductsPanel />

        {/* Home Products from API */}
        <HomeProductsSection />

        {/* Latest News */}
        <NewsSection />
      </section>
    </MainLayout>
  );
}
