"use client";

import { useLocale, useTranslations } from "next-intl";
import { useRouter } from "next/navigation";
import { useHomeProducts } from "@/hooks/useHomeProducts";
import ProductCard from "@/components/ProductCard";
import ProductCardList from "@/components/ProductCardList";
import ProductCardCompact from "@/components/ProductCardCompact";
import type { HomeProductGroup, HomeProductItem } from "@/lib/api/homeProducts";
import type { ProductByCategoryDto } from "@/lib/api/productsByCategory";
import { formatDate } from "@/lib/utils";

export default function HomeProductsSection() {
  const locale = useLocale();
  const t = useTranslations("Home");
  const router = useRouter();

  // Fetch home products with language
  const lang = locale === "vi" ? "vi" : "en";
  const { data, isLoading, isError } = useHomeProducts({ lang });

  const groups = data?.data ?? [];

  // Debug log - detailed analysis
  console.log("[HomeProductsSection] Total groups returned from API:", groups.length);
  console.log("[HomeProductsSection] Groups breakdown:", groups.map(g => ({
    groupId: g.groupId,
    groupName: g.groupName,
    showStyle: g.showStyle,
    productsCount: g.products?.length ?? 0,
    updatedDate: g.updatedDate
  })));

  // Count groups with products
  const groupsWithProducts = groups.filter(g => (g.products?.length ?? 0) > 0);
  console.log("[HomeProductsSection] Groups with products:", groupsWithProducts.length);
  console.log("[HomeProductsSection] Groups without products (will be hidden):", groups.length - groupsWithProducts.length);

  if (isLoading) {
    return (
      <div className="space-y-6">
        {[1, 2].map((i) => (
          <div key={i} className="rounded-xl border border-slate-200 bg-white p-6 shadow-sm">
            <div className="mb-4 h-6 w-48 animate-pulse rounded bg-slate-200" />
            <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 2xl:grid-cols-5">
              {[1, 2, 3, 4, 5].map((j) => (
                <div key={j} className="h-80 animate-pulse rounded-xl bg-slate-100" />
              ))}
            </div>
          </div>
        ))}
      </div>
    );
  }

  if (isError || !groups || groups.length === 0) {
    return (
      <div className="rounded-xl border border-slate-200 bg-white px-4 py-6 text-sm text-slate-600 shadow-sm">
        {isError
          ? t("products.loadError")
          : t("products.empty")}
      </div>
    );
  }

  return (
    <div className="space-y-8">
      {groups.map((group) => (
        <ProductGroupSection key={group.groupId} group={group} locale={locale} router={router} />
      ))}
    </div>
  );
}

// Separate component for each group
function ProductGroupSection({
  group,
  locale,
  router,
}: {
  group: HomeProductGroup;
  locale: string;
  router: ReturnType<typeof useRouter>;
}) {
  const t = useTranslations("Home");
  const tProducts = useTranslations("Products");
  const groupName = locale === "vi" ? group.groupName : group.groupNameEn || group.groupName;
  const products = group.products ?? [];

  // Map HomeProductItem to ProductByCategoryDto format
  const mapProduct = (item: HomeProductItem): ProductByCategoryDto => ({
    id: item.productId,
    code: item.productCode,
    name: item.name,
    nameEn: item.nameEn || item.name,
    price: item.price1, // Original price (giá gốc)
    maxPrice: null, // HomeProductItem doesn't have maxPrice
    originalPrice: item.hasSale ? item.price1 : null,
    activeSaleOff: item.saleOffValue > 0 ? item.saleOffValue : null, // Discount amount per item
    finalPrice: item.finalPrice, // Price after discount
    saleOff: 0, // No percentage discount here
    imageUrl: item.image || "",
    categoryId: item.categoryId,
    categoryName: "",
    isNew: false,
    isActive: true,
    quantity: item.quantity ?? 0,
    dateAdded: item.dateAdded,
  });

  const handleProductClick = (productId: number) => {
    router.push(`/${locale}/products/${productId}`);
  };

  const handleAddToCart = (product: ProductByCategoryDto, quantity: number = 1) => {
    console.log("add-to-cart", product, quantity);
  };

  const handleBuyNow = (product: ProductByCategoryDto, quantity: number = 1) => {
    console.log("buy-now", product, quantity);
  };

  // Render based on showStyle
  const renderProducts = () => {
    switch (group.showStyle) {
      case 1: // List view
        return (
          <div className="space-y-2 sm:space-y-3">
            {products.map((item) => {
              const product = mapProduct(item);
              const displayName = locale === "vi" ? item.name : item.nameEn || item.name;
              return (
                <ProductCardList
                  key={item.productId}
                  product={product}
                  displayName={displayName}
                  onAddToCart={handleAddToCart}
                  onBuyNow={handleBuyNow}
                  onClick={() => handleProductClick(item.productId)}
                />
              );
            })}
          </div>
        );

      case 2: // Compact/Gallery view
        return (
          <div className="grid gap-2 grid-cols-2 xs:grid-cols-3 sm:grid-cols-4 md:grid-cols-5 lg:grid-cols-6 xl:grid-cols-8 sm:gap-3">
            {products.map((item) => {
              const product = mapProduct(item);
              const displayName = locale === "vi" ? item.name : item.nameEn || item.name;
              return (
                <ProductCardCompact
                  key={item.productId}
                  product={product}
                  displayName={displayName}
                  onAddToCart={(p) => handleAddToCart(p, 1)}
                  onClick={() => handleProductClick(item.productId)}
                />
              );
            })}
          </div>
        );

      default: // Grid view (showStyle = 0 or unknown)
        return (
          <div className="grid gap-3 grid-cols-2 sm:gap-4 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
            {products.map((item) => {
              const product = mapProduct(item);
              const displayName = locale === "vi" ? item.name : item.nameEn || item.name;
              return (
                <ProductCard
                  key={item.productId}
                  product={product}
                  displayName={displayName}
                  onAddToCart={handleAddToCart}
                  onBuyNow={handleBuyNow}
                  onClick={() => handleProductClick(item.productId)}
                />
              );
            })}
          </div>
        );
    }
  };

  if (products.length === 0) {
    return null;
  }

  return (
    <section className="rounded-xl border border-slate-200 bg-white p-3 shadow-sm sm:p-4">
      <div className="mb-3 flex flex-wrap items-center justify-between gap-2 sm:mb-4">
        <div>
          <h2 className="text-base font-semibold text-slate-900 sm:text-lg">{groupName}</h2>
          {group.updatedDate && (
            <p className="mt-0.5 text-xs text-slate-500">
              {tProducts("updated")}{" "}
              {formatDate(group.updatedDate, "dd/MM/yyyy")}
            </p>
          )}
        </div>
        <button
          onClick={() => router.push(`/${locale}/products?groupId=${group.groupId}`)}
          className="text-sm font-medium text-primary hover:text-primary-dark"
        >
          {t("featured.viewAll")}
        </button>
      </div>
      {renderProducts()}
    </section>
  );
}
